        SELECT_THIS_SONG_YES_THIS_SOUNDS_SPLENDID_NO                            = 6795,  -- Select this song? Yes, this sounds splendid! No, I've changed my tune.
        THIS_SONG_CANNOT_YET_BE_PLAYED                                          = 6796,  -- This song cannot yet be played.
        HANG_ON_I_HAVE_AN_AMAZING_ANNOUNCEMENT                                  = 6797,  -- Hang on! I have an amazing announcement!
        THE_HALLOWED_HALLS_OF_YOUR_HOUSE_ARE_EVEN                               = 6798,  -- The hallowed halls of your house are even more exciting! Why? Because now there's a second floor, kupo!
        BUT_BEFORE_YOU_BASH_YOUR_WAY_IN_I                                       = 6799,  -- But before you bash your way in, I've got a trifling task for you to tackle.
        CAPRICIOUS_MITHRA_CUBS_HAVE_CAJOLED_CRITICAL_INFORMATION_OUT            = 6800,  -- Capricious Mithra cubs have cajoled critical information out of the M.H.M.U., and I want you to wrest it from them!
        VISIT_THE_THREE_NATIONS_AND_QUESTION_THEM_KUPO                          = 6801,  -- Visit the three nations and question them, kupo!
        NOW_YOU_KNOW_THE_NITTY_GRITTY_SO_ENJOY                                  = 6802,  -- Now you know the nitty-gritty, so enjoy your new floor, kupo!
        KUPOPO_YOU_MEAN_YOU_ALREADY_KNOW                                        = 6803,  -- Kupopo? You mean you already know?
        MAGNIFICENT_AND_MARVELOUS_THEN_PROCEED_WITHOUT_DELAY                    = 6804,  -- Magnificent and marvelous! Then proceed without delay!
        ENJOY_EXTRA_SPACE_TO_STORE_YOUR_SUNDRIES                                = 6805,  -- Enjoy extra space to store your sundries!
        REMODEL_YOUR_ROOM_TO_FIT_YOUR_FINICKY_TASTES                            = 6806,  -- Remodel your room to fit your finicky tastes!
        INCORPORATE_OSTENTATIOUS_OVERSEAS_OBJECTS_ALL_THIS_AND_MORE             = 6807,  -- Incorporate ostentatious overseas objects! All this and more!
        BUT_ONLY_ON_THE_SECOND_FLOOR_KUPO_I                                     = 6808,  -- But only on the second floor, kupo. I like the first floor as it is.
        AND_AS_FOR_YOUR_POTTED_PLANTS_THEY_ONLY                                 = 6809,  -- And as for your potted plants--they only persevere on the ground, kupo.
        AND_MOGHANCEMENT_EFFECTS_ONLY_ACTIVATE_FOR_FURNISHINGS_FITTED           = 6810,  -- And moghancement effects only activate for furnishings fitted to the first floor.
        WISH_WE_COULD_HELP_MORE_BUT_WE_SPEND                                    = 6811,  -- Wish we could help more, but we spend enormous amounts of energy on one floor already!
        GO_FORTH_AND_FROLIC_IN_YOUR_NEW_ABODE                                   = 6812,  -- Go forth and frolic in your new abode, kupo!
        YOU_CAN_ACCESS_THE_ANTECHAMBERS_FROM_THE_FRONT                          = 6813,  -- You can access the antechambers from the front door. Enjoy!
        MIGHT_BRING_A_CERTAIN_JE_NE_SAIS_QUOI                                   = 6814,  -- % might bring a certain je ne sais quoi to your Mog House, kupo!
        WHAT_S_THIS_THEN_SOMEONE_GAVE_YOU_THIS                                  = 6815,  -- What's this, then? Someone gave you this envelope, did they?
        WH_WHAT_IS_THIS                                                         = 6816,  -- Wh-what is this!?
        THIS_RUBBISH_DOES_NOT_FOOL_ME_I_KNOW                                    = 6817,  -- This rubbish does not fool me! I know a forgery when I see one.
        MOST_UNPLEASANT_DO_NOT_SPEAK_TO_ME_OF                                   = 6818,  -- Most unpleasant. Do not speak to me of this matter again!
        YOU_CALLED_FOR_ME_YOUR_MAJESTY                                          = 6819,  -- You called for me, Your Majesty?
        FRANCMAGE_I_WAS_NOT_EXPECTING_YOU_SO_SOON                               = 6820,  -- Francmage? I was not expecting you so soon. Monarlais...tell him.
        YES_SIRE                                                                = 6821,  -- Yes, sire.
        FRANCMAGE_I_VE_SUMMONED_YOU_HERE_TODAY_TO                               = 6822,  -- Francmage, I've summoned you here today to talk about one thing--the Northlands investigation.
        OH_YES_THAT_THOSE_BASTOKER_HUMES_ARE_CAUSING                            = 6823,  -- Oh, yes, that. Those Bastoker Humes are causing no end of trouble--saying they want to investigate here, there, and the other place...
        IT_IS_TRUE_THE_HUMES_ARE_FOOLS_AND                                      = 6824,  -- It is true! The Humes are fools, and no better. Can they truly believe that some ancient power lies hidden in that forsaken wasteland?
        HAH_DO_THEY_HOPE_TO_FIND_THE_GATES                                      = 6825,  -- Hah! Do they hope to find the gates to eternal Paradise there, in that lair of fiends most uncouth? Preposterous!
        WE_MUST_TAKE_CONTROL_OF_THIS_SITUATION_IMMEDIATELY                      = 6826,  -- We must take control of this situation immediately. Still, we cannot let them walk about the Northlands freely. Who knows what they're plotting under the guise of this investigation.
        FRANCMAGE_LISTEN_GO_WITH_THE_INVESTIGATION_PARTY_AND                    = 6827,  -- Francmage, listen. Go with the investigation party, and keep a close eye on what our foreign friends do. They are up to something, it is certain.
        I_AM_SURE_NOTHING_WILL_COME_OF_THIS                                     = 6828,  -- I am sure nothing will come of this, but in case they do find something in that wasteland, do not let them take it. Understood?
        AS_YOU_COMMAND_MY_LORD_I_WOULD_GIVE                                     = 6829,  -- As you command, my lord. I would give the very blood that runs in my veins if it were to further the cause of our kingdom. You can rely on me.
        THESE_FOREIGNERS_ARE_WILY_AND_FAITHLESS_NEVER_LET                       = 6830,  -- These foreigners are wily and faithless. Never let down your guard, and may the Goddess of the Dawn protect you in Her mercy.
        THE_KING_HAS_TAKEN_A_BEAUTIFUL_QUEEN_AND                                = 6831,  -- The king has taken a beautiful queen, and I think a splendid addition to the royal family is not far off. An heir, perhaps...
        WE_PEOPLE_OF_SAN_D_ORIA_TOO_MUST                                        = 6832,  -- We people of San d'Oria, too, must ever look to the future. The Elvaan must never fall behind foreigners, in power or faith.
        I_UNDERSTAND_YOUR_GRACE                                                 = 6833,  -- I understand, Your Grace.
        VERY_GOOD_DO_WELL_FRANCMAGE                                             = 6834,  -- Very good. Do well, Francmage.
        YES_SIRE_MY_LIFE_FOR_THE_KINGDOM                                        = 6835,  -- Yes, sire! My life for the Kingdom!
        AS_I_THOUGHT_THERE_IS_NOTHING_HERE_ONLY                                 = 6836,  -- As I thought, there is nothing here... Only barren wastelands as far as the eye can see.
        BUT_THERE_IS_SOMETHING_WRONG_ABOUT_THIS_PLACE                           = 6837,  -- But there is something wrong about this place, I can feel it. I don't think-wink we should leave Xarcabard yet.
        I_AGREE_MY_NOSE_HAS_NEVER_FAILED_ME                                     = 6838,  -- I agree. My nose has never failed me, but I don't smell anything. That's not normal. Something really terrrible must've happened here a long time ago.
        RIDICULOUS_WE_CANNOT_BASE_OUR_DECISIONS_ON_YOUR                         = 6839,  -- Ridiculous. We cannot base our decisions on your feelings alone. You can stay and look for whatever terrible thing is supposed to be here, but I--
        HELP_COME_QUICK_RAOGRIMM_AND_CORNELIA_THEY                              = 6840,  -- Help! Come quick! Raogrimm and Cornelia, they--
        ULRICH_WHAT_HAPPENED                                                    = 6841,  -- Ulrich? What happened!?
        WE_WERE_ATTACKED_BY_FIENDS_AND_RAOGRIMM_AND                             = 6842,  -- We were attacked by fiends, and Raogrimm and Cornelia fell down a crevice...
        OH_NO_OH_NO                                                             = 6843,  -- Oh, no! Oh, no!
        GRR_WHERE                                                               = 6844,  -- Grr! Where!?
        THIS_WAY                                                                = 6845,  -- This way!
        RAOGRIMM_AND_CORNELIA_WHERE_COULD_THEY_HAVE_GONE                        = 6846,  -- Raogrimm and Cornelia...where could they have gone?
        WE_HAVE_TO_ASSUME_THE_WORRRST_IF_I                                      = 6847,  -- We have to assume the worrrst. If I can't find them, no one can.
        WHY_MUST_HUMES_AND_GALKA_BE_SO_IRRESPONSIBLE                            = 6848,  -- Why must Humes and Galka be so irresponsible!? It is their fault for wandering off without telling us!
        THERE_ARE_TOO_FEW_OF_US_LEFT_TO                                         = 6849,  -- There are too few of us left to continue. I say we go back. Besides, we would find nothing even if we stayed.
        I_SECOND_THAT_I_VE_HAD_ENOUGH_OF                                        = 6850,  -- I second that. I've had enough of this crrreepy place anyway.
        B_BUT_THERE_ARE_STILL_PLACES_WE_HAVEN                                   = 6851,  -- B-but, there are still places we haven't looked--
        WE_HAVE_SEEN_ENOUGH_THERE_IS_NOTHING_HERE                               = 6852,  -- We have seen enough. There is nothing here but dust and ruins.
        WE_ACCOMPLISHED_NOTHING_BUT_LOSING_TWO_MEMBERS_OF                       = 6853,  -- We accomplished nothing but losing two members of our party and wasting an extraordinary amount of time...
        YEAH_YOU_RE_RIGHT_THIS_WHOLE_EXPEDITION_WAS                             = 6854,  -- Yeah, you're right. This whole expedition was a failure. Let's head back tomorrow.
        ULRICH_TELL_ME_SOMETHING_WAS_IT_REALLY_AN                               = 6855,  -- Ulrich. Tell me something... Was it really an accident?
        WHAT_DO_YOU_MEAN                                                        = 6856,  -- What do you mean?
        IS_IT_NOT_TRUE_THAT_THERE_IS_SOME                                       = 6857,  -- Is it not true that there is some...shall we say, tension, between Humes and Galka in Bastok these days?
        ARE_YOU_ACCUSING_ME_OF_SOMETHING_ELVAAN                                 = 6858,  -- Are you accusing me of something, Elvaan?
        HAH_CALM_DOWN_I_DO_NOT_CARE_IF                                          = 6859,  -- Hah! Calm down. I do not care if it was an accident or not. I care even less about your little country's problems.
        JUST_DO_NOT_CAUSE_ANY_MORE_TROUBLE_WITH                                 = 6860,  -- Just...do not cause any more trouble with such trivial matters while I am around. That is all.
        ID_6861                                                                 = 6861,  -- ...
        IT_IS_QUITE_LATE_TO_BE_UP_AND                                           = 6862,  -- It is quite late to be up and about, Sir Francmage. Is something wrong?
        AH_COURISAILLE_IT_S_NOTHING_I_COULD_NOT                                 = 6863,  -- Ah, Courisaille. It's nothing. I could not sleep, so I decided to take a walk. Leave me; I am fine.
        YES_SIR                                                                 = 6864,  -- Yes, sir.
        NO_NOT_YOU_RAOGRIMM_WHAT_DO_YOU_MEAN                                    = 6865,  -- No! Not you...? Raogrimm? What do you mean!? He died in an accident! I know nothing!
        SIR_FRANCMAGE_ARE_YOU_ALL_RIGHT_SIR                                     = 6866,  -- Sir Francmage? Are you all right, sir?
        STOP_DO_NOT_COME_ANY_FURTHER_NO_NOOO                                    = 6867,  -- Stop! Do not come any further! No, nooo--
        S_SIR_FRANCMAGE                                                         = 6868,  -- ... S-Sir...Francmage?
