        YOU_ARE_TOO_LATE_I_HAVE_ALREADY_AWAKENED_2                              = 11000,  -- You are too late... I have already awakened.
        YOUR_ANGER_COWARDICE_ENVY_ARROGANCE_AND_APATHY_FROM                     = 11001,  -- Your anger, cowardice, envy, arrogance, and apathy...from these I will spread the bane that will destroy Vana'diel.
