        ANOTHER_GROUP_OF_PLAYER_CHARACTERS_IS_CURRENTLY_OCCUPYING               = 11243,  -- Another group of player characters is currently occupying Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia].
        THE_TIME_AND_DESTINATION_FOR_YOUR_FORAY_INTO_2                          = 11244,  -- The time and destination for your foray into Dynamis has been recorded on your %.
