        THE_FOLLOWING_INFORMATION_REGARDS_THE_MATCH_I_AM                        = 11619,  -- The following information regards the match I am currently authorized to teleport you to...
        TELEPORT_RIGHT_AWAY_NOT_YET                                             = 11620,  -- Teleport? Right away. Not yet.
        I_AM_SORRY_BUT_I_CANNOT_TELEPORT_YOU                                    = 11621,  -- I am sorry, but I cannot teleport you at this time.
        I_AM_SORRY_BUT_I_CANNOT_TELEPORT_YOU_2                                  = 11622,  -- I am sorry, but I cannot teleport you at this time. Please return when there are less than twenty-four hours remaining until the next match.
