        CURRENTLY_THERE_ARE_NO_SPECIAL_RULES_BEING_IMPLEMENTED                  = 11624,  -- Currently, there are no special rules being implemented.
        THE_NEXT_SCHEDULED_BALLISTA_MATCH_IS_AREA_MATCHUP                       = 11625,  -- The next scheduled Ballista match is: Area: [Jugner Forest/Pashhow Marshlands/Meriphataud Mountains] Matchup: [San d'Oria vs Bastok/Bastok vs Windurst/Windurst vs San d'Oria] Level Restriction: [None/@/@/30/40/50/60/] Participation Fee: # gil Match Format: [All or Nothing * Normal Items Allowed/All or Nothing * Normal Items Restricted/Best of Three * Normal Items Allowed]
        ENTRIES_ARE_NOW_BEING_ACCEPTED                                          = 11626,  -- Entries are now being accepted.
