        WHILE_WEARING_DURING_A_MATCH_YOU_WILL_BE                                = 11629,  -- While wearing % during a match, you will be able to hear the orders of your nation's Pursuivant. His advice will aid you in battle.
        ALSO_YOU_WILL_BE_INFORMED_OF_ALL_THE                                    = 11630,  -- Also, you will be informed of all the latest match information when entering select cities.
        WOULD_YOU_LIKE_YES_NO                                                   = 11631,  -- Would you like %? Yes. No.
        RETURN_YOUR_YES_NO                                                      = 11632,  -- Return your %? Yes. No.
        OBTAINED_2                                                              = 11633,  -- Obtained: %.
        BY_CARRYING_WITH_YOU_DURING_A_BALLISTA_MATCH                            = 11634,  -- By carrying % with you during a Ballista match, any temporary item you quarry will be automatically placed in your bag without you having to select whether you wish to keep it, use it, or throw it away.
        WHEN_YOUR_INVENTORY_IS_FULL_OR_YOU_CANNOT                               = 11635,  -- When your inventory is full, or you cannot carry any more of a certain item, the newly quarried item will be automatically discarded. If you wish, I can lend you one of these shovels, free of charge.
        BORROW_YES_NO                                                           = 11636,  -- Borrow %? Yes. No.
