        THE_RANKING_INFORMATION_GIVEN_BY_MARSHALS_IN_JEUNO                      = 11995,  -- The ranking information given by Marshals in Jeuno may be slightly older than the current data. For the most up-to-date numbers, we suggest that you speak with the officials stationed in each partcipating Ballista area.
        PLEASE_NOTE_THAT_BECAUSE_THE_POINT_REGISTRATION_PERIOD                  = 11996,  -- Please note that because the point registration period for the previous match has not yet ended, your ranking may change. We ask that you check back later for the final results.
        YOUR_PERFORMANCE_IN_THE_LAST_MATCH_EARNED_YOU                           = 11997,  -- Your performance in the last match earned you a place in the overall ranking. However, because you did not check with a Herald before the records were destroyed, you have lost the opportunity to claim your prize.
        YOUR_POINTS_HAVE_BEEN_REGISTERED_CONGRATULATIONS_YOU_ARE_2              = 11998,  -- Your points have been registered. Congratulations! You are currently in first place!
        CONGRATULATIONS_BALLISTA_POINT_RANKING_REGISTRATION_FOR_THE_PREVIOUS    = 11999,  -- Congratulations! Ballista Point Ranking registration for the previous match has come to a close, and your final overall rank is #! You shall be presented with % and a new title.
        GOOD_SHOW_BALLISTA_POINT_RANKING_REGISTRATION_FOR_THE                   = 12000,  -- Good show! Ballista Point Ranking registration for the previous match has come to a close, and your final rank among participating [/warriors/monks/white mages/black mages/red mages/thieves/paladins/dark knights/beastmasters/bards/rangers/samurais/ninjas/dragoons/summoners/blue mage/corsairs/puppetmasters/dancers/scholars/geomancers/rune fencers] (# total) is first! You shall be presented with % and a new title.
        WELL_DONE_BALLISTA_POINT_RANKING_REGISTRATION_FOR_THE                   = 12001,  -- Well done! Ballista Point Ranking registration for the previous match has come to a close, and your final overall rank is #! In addition, your final rank among participating [/warriors/monks/white mages/black mages/red mages/thieves/paladins/dark knights/beastmasters/bards/rangers/samurais/ninjas/dragoons/summoners/blue mage/corsairs/puppetmasters/dancers/scholars/geomancers/rune fencers] (# total) is first! You shall be presented with % or %, as well as a new title.
        WHILE_OUR_RECORDS_WILL_CLEARLY_INDICATE_THAT_YOU                        = 12002,  -- While our records will clearly indicate that you were rewarded both chevrons, Ballista regulations only allow participants to wear one at a time. Therefore, you must choose which one you wish to receive at this time.
        PLEASE_SELECT_ONE                                                       = 12003,  -- Please select one... %. %.
        YOU_ARE_CURRENTLY_WEARING_IF_YOU_WISH_TO                                = 12004,  -- You are currently wearing %. If you wish to accept the chevron you earned this match, you must return the one you currently possess.
        ACCEPT_THE_YES_NO                                                       = 12005,  -- Accept the %? Yes. No.
