        GENERAL_PARTICIPATION_IS_CURRENTLY_BEING_ALLOWED_FOR_THE                = 12878,  -- General participation is currently being allowed for the next Diorama Ballista match. [There is no level limit set/The level limit is set to 60/The level limit is set to 50/The level limit is set to 40/The level limit is set to 30/The level limit is set to 20/The level limit is set to 10].
        I_HAVE_BEEN_GIVEN_AUTHORIZATION_BY_THE_ACTING                           = 12879,  -- I have been given authorization by the acting Master of Ceremonies to provide any adventurer who wishes to take part in the event with %, as well as teleport him or her to the battlefield (for a small fee of # gil).
        DO_YOU_WISH_TO_PARTICIPATE_YES_NO                                       = 12880,  -- Do you wish to participate? Yes. No.
        WHEN_YOU_HAVE_MADE_YOUR_PREPARATIONS_SHOW_ME                            = 12881,  -- When you have made your preparations, show me your % and I shall teleport you to the Diorama.
        MANY_YEARS_AGO_BEFORE_CONFLICT_WAS_BANNED_MY                            = 12882,  -- Many years ago, before Conflict was banned, my master, the almighty Abdhaljs, honed his magical battle techniques on the fields of Ballista.
        AND_NOW_WITH_THE_RECENT_REINSTATEMENT_OF_THE                            = 12883,  -- And now with the recent reinstatement of the exercises, the great mage has been working feverishly to complete a creation he believes can be of great assistance to Conflict--Diorama Abdhaljs-Ghelsba.
        WHAT_IS_A_DIORAMA_SIMILAR_TO_THE_ONE                                    = 12884,  -- What is a Diorama? Similar to the one used in the popular children's board game Battleista, Diorama Abdhaljs is a miniature version of an actual location in Vana'diel.
        HOWEVER_THERE_IS_ONE_THING_THAT_SETS_DIORAMA                            = 12885,  -- However, there is one thing that sets Diorama Abdhaljs apart from its counterpart. In the place of wooden game pieces, living, breathing warriors are used!
        HOW_IS_THAT_POSSIBLE_YOU_ASK_WELL_IN                                    = 12886,  -- How is that possible, you ask? Well, in his studies, my master was able to unlock the secrets of the ancient magic known as Mini--a forbidden spell with the power to reduce objects to a fraction of their original size.
        BY_USING_THE_INCANTATIONS_INSCRIBED_ON_CODICES_AUTHORED                 = 12887,  -- By using the incantations inscribed on codices authored by Abdhaljs, players can be temporarily shrunk down and teleported to the miniature battlefield hidden on a secluded island somewhere in the Tavnazian Archipelago.
        IT_IS_ALL_PERFECTLY_SAFE_AND_THE_ALL                                    = 12888,  -- It is all perfectly safe, and the all-seeing Abdhaljs guarantees that you will be satisfied with your experience within his creation (though no refunds will be offered if you are not).
        A_VALID_OR_IS_REQUIRED_FOR_ACCESS_TO                                    = 12889,  -- A valid %, %, %, or % is required for access to the Diorama.
        PRESENT_ONE_TO_ME_WHEN_YOU_HAVE_COMPLETED                               = 12890,  -- Present one to me when you have completed your preparations.
        WHAT_WOULD_YOU_LIKE_TO_KNOW_ABOUT_MAKING                                = 12891,  -- What would you like to know? About making reservations. About reservation guidelines. About reservation status. About the waiting list. Return.
        THE_DIORAMA_CAN_BE_RESERVED_IN_BLOCKS_OF                                = 12892,  -- The Diorama can be reserved in blocks of two hours (Earth time).
        RESERVATIONS_CAN_BE_MADE_FOR_SAME_DAY_BLOCKS                            = 12893,  -- Reservations can be made for same-day blocks, as well as blocks two days in advance. For example, you could currently reserve the two-hour block from to .
        IF_NO_RESERVATIONS_HAVE_BEEN_MADE_FOR_THE                               = 12894,  -- If no reservations have been made for the current block, or a person fails to reconfirm his or her reservation, other adventurers may be granted access to the area.
        AT_THE_TIME_OF_THE_RESERVATION_THE_CLIENT                               = 12895,  -- At the time of the reservation, the client will be required to decide on a level restriction. Once this is set, % inscribed with the Diorama access time and the level restriction will be presented.
        IF_THERE_IS_NO_RESERVATION_FOR_THE_CURRENT                              = 12896,  -- If there is no reservation for the current two-hour block, or a person fails to reconfirm his or her reservation, other adventurers may be granted access to the area.
        THE_PERSON_WHO_POSSESSES_THE_ORIGINAL_IS_AUTOMATICALLY                  = 12897,  -- The person who possesses the original % is automatically named the Master of Ceremonies (MC), and will be granted authorization to change various Diorama access settings, as well as Ballista-related rules within the area.
        RESERVATIONS_ARE_ONLY_GOOD_FOR_BLOCKS_OF_TWO                            = 12898,  -- Reservations are only good for blocks of two hours. When a party's time in the Diorama is up, all participants will be teleported back here to the Ru'Lude Gardens.
        BY_USING_ADVENTURERS_CAN_CREATE_ANY_PERSON_WHO                          = 12899,  -- By using %, adventurers can create %. Any person who possesses one of these pages will be granted access to the Diorama from the time indicated on the bottom.
        ALSO_MORE_CAN_BE_MADE_BY_SIMPLY_USING                                   = 12900,  -- Also, more % can be made by simply using the page as one would a normal item.
        YOU_CAN_NOW_MAKE_AND_CONFIRM_RESERVATIONS_USING                         = 12901,  -- You can now make and confirm reservations using the reservation status list.
        THE_STATUS_OF_EACH_TIME_BLOCK_WILL_BE                                   = 12902,  -- The status of each time block will be displayed in symbols. The symbols' meanings are as follows: H: The reservation documents have been misplaced. |: No reservation. OM: Official match.
        YOU_CAN_SELECT_A_BLOCK_MARKED_WITH_TO                                   = 12903,  -- You can select a block marked with | to make a reservation.
        A_MARK_REPRESENTS_A_BLOCK_THAT_IS_ALREADY                               = 12904,  -- A ~ mark represents a block that is already reserved. ~! designates a reserved block whose team is still recruiting. You can select the block to find out more.
        IF_NOT_A_SINGLE_ADVENTURER_POSSESSING_THE_APPROPRIATE                   = 12905,  -- If not a single adventurer possessing the appropriate % or % reports for reservation reconfirmation (up until 15 Earth minutes before the reserved time), the reservation will be cancelled.
        ONCE_THE_RESERVATION_HAS_BEEN_CANCELLED_THE_AND                         = 12906,  -- Once the reservation has been cancelled, the % and all % will become void. At this time, other adventurers will have the opportunity to immediately reserve the area.
        AH_WELCOME_I_SEE_THAT_YOU_ARE_ON                                        = 12907,  -- Ah, welcome, %! I see that you are on the Ballista Royale participation list. I will now present you with the item you will need to enter the special Ballista area being used for the event.
        PLEASE_REVIEW_THE_TIME_INSCRIBED_ON_THE_BOTTOM                          = 12908,  -- Please review the time inscribed on the bottom of the codex. This is when the check-in period will begin. At that time, please show me the item once more and I shall teleport you to the Diorama.
        THE_ENTRY_PERIOD_WILL_END_AND_BRIEFING_WILL                             = 12909,  -- The entry period will end and briefing will commence # [minute/minutes] (Earth time) after the check-in period starts.
        THE_MAXIMUM_NUMBER_OF_MEMBERS_ALLOWED_ON_ONE                            = 12910,  -- The maximum number of members allowed on one team is #. Entries during matches are [not allowed/allowed], and entry cancellation during matches is [not permitted/permitted]. Also, players with the same job are not allowed to serve on the same team, [and support jobs are prohibited./though there are no restrictions on support jobs.]
        THE_MAXIMUM_LEVEL_ALLOWED_IS_THE_MINIMUM_LEVEL                          = 12911,  -- The maximum level allowed is [not set/set to 60/set to 50/set to 40/set to 30/set to 20/set to 10]. The minimum level required is [not set/set to 60/set to 50/set to 40/set to 30/set to 20/set to 10].
        MATCHES_WILL_BE_PLAYED_IN_THE_STYLE_WITH                                = 12912,  -- Matches will be played in the [all or nothing/best of three/] style, with [/single-]match length set at [10 minutes/15 minutes/20 minutes/30 minutes/45 minutes/1 Vana'diel day (57 minutes, 36 seconds)/60 minutes/] (Earth time). Normal item usage is [not allowed/allowed] and the maximum number of temporary items carryable is [10/15/20].
        PARTICIPANTS_WILL_BE_ABLE_TO_CHOOSE_WHETHER_OR                          = 12913,  -- Participants will[ not/] be able to choose whether or not they can keep Petras they find, and Petras or items will[/ not] be found with every /quarry. The maximum number of Petras a player can score at one time is [1/2/3/4/5/10/15/not set], and a match will [not be called as a result of a large lead/be called the moment one team leads by 10/be called the moment one team leads by 20/be called the moment one team leads by 30/be called the moment one team leads by 40/be called the moment one team leads by 50/be called the moment one team leads by 60/be called the moment one team leads by 70/be called the moment one team leads by 80/be called the moment one team leads by 90/be called the moment one team leads by 100].
