        DEBUG_FOR_WHEN_AFTER_PHASE_1_AFTER_PHASE                                = 12932,  -- DEBUG: For when? After phase 1. After phase 2. After phase 3. After phase 4. After phase 5. After phase 6. After phase 7. After phase 8. After phase 9. After phase 10. After phase 11. After phase 12. After phase 13. After phase 14. After phase 15. After phase 16. After phase 17. After phase 18. After phase 19. After phase 20. After phase 21. After phase 22. After phase 23. After phase 24. Nothing.
