        ONLY_THOSE_WITH_ARE_ALLOWED_TO_PASS_BE                                  = 15010,  -- Only those with % are allowed to pass. Be on your way.
        WHAT_S_THIS_AH_YOU_MUST_BE_ONE                                          = 15011,  -- What's this? %? Ah, you must be one of the [adventurers/Allied soldiers] participating in the Voidwatch operation. Pray forgive my oversight.
        IF_YOU_COULD_WAIT_BUT_ONE_MOMENT_I                                      = 15012,  -- If you could wait but one moment, I shall announce your arrival.
