        YOU_ADJUSTED_THE_WAYPOINT_WITH_YOUR                                     = 15354,  -- You adjusted the waypoint with your %.
        YOU_WERE_UNABLE_TO_SATISFACTORILY_ADJUST_THE_WAYPOINT                   = 15355,  -- You were unable to satisfactorily adjust the waypoint.
        AN_ENIGMATIC_CONTRIVANCE_HOVERS_IN_SILENCE                              = 15356,  -- An enigmatic contrivance hovers in silence...
        LEANING_IN_CLOSELY_TO_THE_DEVICE_ONE_CAN                                = 15357,  -- Leaning in closely to the device, one can make out miniscule etchings that read, Trade various crystals to this waypoint to receive kinetic units that may be used when you wish to warp to another locale.
        TRAVELERS_MAY_NOT_POSSESS_MORE_THAN_AT_A                                = 15358,  -- Travelers may not possess more than # at a given time. Should someone trade an amount of crystals that would result in a surplus of kinetic units, those units will be lost to the aether.
