        UNABLE_TO_PROCEED_CHAINS_OF_PROMATHIA_HAS_NOT                           = 15367,  -- Unable to proceed. Chains of Promathia has not been installed.
        YOU_WILL_NOT_BE_ASKED_TO_CONFIRM_YOUR                                   = 15368,  -- You will not be asked to confirm your choice of destination. Switching to simple teleporation mode.
        YOU_WILL_BE_ASKED_TO_CONFIRM_YOUR_CHOICE                                = 15369,  -- You will be asked to confirm your choice of destination. Returning to normal teleportation mode.
