        YOU_MAY_USE_UP_TO_MORE_SPARKS_OF                                        = 15618,  -- You may use up to # more sparks of eminence to purchase items.
        EXCHANGE_FOR_WHAT_SPARKS_ITEMS_SKILL_INCREASING_TOMES                   = 15619,  -- Exchange for what? (Sparks: #) Items. Skill-increasing tomes. Equ. Lv.1 - 9. (Up to #) Equ. Lv.10 - 19. (Up to #) Equ. Lv.20 - 29. (Up to #) Equ. Lv.30 - 39. (Up to #) Equ. Lv.40 - 50. (Up to #) Equ. Lv.51 - 70. (Up to #) Equ. Lv.71 - 98. (Up to #) Equ. Lv.99. (Up to #) 10. Trust. Exchange A.M.A.N. currencies. Exchange Seven Treasures. Wise words on Records of Eminence. Nothing.
