        RESETTING_REWARDS_WILL_INCREASE_THE_NUMBER_OF_DEEDS                     = 15679,  -- Resetting rewards will increase the number of deeds required but will let you reobtain items you have previously received.
        YOU_ARE_ABLE_TO_RESET_YOUR_REWARDS_FOR                                  = 15680,  -- You are able to reset your rewards for # deed[/s].
        RESET_REWARDS_YES_RESET_NO                                              = 15681,  -- Reset rewards? Yes. (Reset ##) No.
        YOU_HAVE_NOT_YET_RECEIVED_SOME_REWARDS_RESETTING                        = 15682,  -- You have not yet received some rewards. Resetting means that you will be unable to obtain them. Are you sure?
        REALLY_RESET_REWARDS_YES_RESET_NO                                       = 15683,  -- Really reset rewards? Yes. (Reset ##) No.
        REWARDS_HAVE_BEEN_RESET                                                 = 15684,  -- Rewards have been reset.
        WHY_I_NEVER_ONE_WITH_SUCH_A_MEAGER                                      = 15685,  -- Why I never! One with such a meager aura is not fit to be in my presence, let alone speak to me!
        THE_NERVE_OF_SOME_PEOPLE_I_REFUSE_TO                                    = 15686,  -- The nerve of some people! I refuse to speak with anyone who has yet to receive % from Lady Syndella!
        WELL_IT_TOOK_YOU_LONG_ENOUGH_TO_COME                                    = 15687,  -- Well, it took you long enough to come speak with me! I have been sending furtive glances your way for what seems like an eternity now!
        YOU_KNOW_YOU_REALLY_SHOULD_GIVE_UP_ON                                   = 15688,  -- You know, you really should give up on helping Jamal with his utterly pointless research.
        LIKE_EVERYTHING_HE_DOES_IT_IS_DESTINED_TO                               = 15689,  -- Like everything he does, it is destined to end in abject failure.
        HM_WHAT_DO_YOU_MEAN_IT_IS_NONE                                          = 15690,  -- Hm? What do you mean it is none of my business?
        DO_YOU_KNOW_WHO_YOU_ARE_SPEAKING_TO                                     = 15691,  -- Do you know who you are speaking to? I am Marjory, the most brilliant magician this realm has ever seen, and the foremost expert on Trust research!
        I_AM_SOMEWHAT_SURPRISED_YOU_DID_NOT_ALREADY                             = 15692,  -- I am somewhat surprised you did not already know that. At any rate, there is a certain matter I need your help with.
        WILL_YOU_HELP_HER_SURE_NO_THANKS                                        = 15693,  -- Will you help her? Sure. No thanks.
        H_HOW_DARE_YOU_DECLINE_MY_OFFER_YOU                                     = 15694,  -- H-how dare you decline my offer... You will come to regret this, I assure you!
        I_AM_PLEASED_TO_SEE_YOU_MAKE_SUCH                                       = 15695,  -- I am pleased to see you make such a wise decision! Hehe... I cannot wait to see that buffoon Jamal choke on his own words!
        NOW_THEN_JAMAL_LIKES_TO_EQUATE_THE_DARKNESS                             = 15696,  -- Now then! Jamal likes to equate the darkness of alter egos to the root of all evil or some such nonsense, but as with most things, he could not be more wrong.
        THESE_ARE_JUST_MY_THOUGHTS_ON_THE_ISSUE                                 = 15697,  -- These are just my thoughts on the issue, but...
        YOU_SEE_UNLIKE_JAMAL_I_DO_NOT_BELIEVE                                   = 15698,  -- You see, unlike Jamal, I do not believe that Trust magic is something meant to be cast outwards from its user.
        NO_TRUST_MAGIC_IS_DESIGNED_TO_LOOK_WITHIN                               = 15699,  -- No, Trust magic is designed to look within us. In other words...
        THE_ALTER_EGOS_TAKE_SHAPE_DUE_TO_THE                                    = 15700,  -- The alter egos take shape due to the power contained within a kind of unseen pipeline inside of us that conveys our feelings and thoughts to them.
        THAT_GOT_ME_THINKING_IF_ONE_COULD_SOMEHOW                               = 15701,  -- That got me thinking! If one could somehow boost the amount of those feelings and thoughts being sent...
        IT_COULD_LEAD_TO_THE_ALTER_EGO_ITSELF                                   = 15702,  -- It could lead to the alter ego itself becoming even more powerful!
        HM_WHAT_DO_YOU_MEAN_YOU_DON_T                                           = 15703,  -- Hm? What do you mean you don't understand? You really are quite dense, aren't you?
        WELL_I_AM_STUCK_WITH_YOU_I_GUESS                                        = 15704,  -- Well, I am stuck with you, I guess, so you will need a few things if you are to help me with my research.
        FIRST_OF_ALL_YOU_WILL_NEED_THIS_SPECIAL                                 = 15705,  -- First of all, you will need this special diamond.
        IT_IS_CAPABLE_OF_DETECTING_THE_FEELINGS_AND                             = 15706,  -- It is capable of detecting the feelings and thoughts you direct at the alter ego you are summoning.
        THIS_DIAMOND_THEN_STORES_THEM_WITHIN_ITS_CRYSTALLINE                    = 15707,  -- This diamond then stores them within its crystalline confines.
        ONCE_IT_HAS_GATHERED_A_CERTAIN_AMOUNT_OF                                = 15708,  -- Once it has gathered a certain amount of thoughts and feelings, it will change color.
        SO_BASICALLY_I_NEED_YOU_TO_USE_YOUR                                     = 15709,  -- So basically, I need you to use your Trust magic until you see the diamond change color!
        TO_HELP_YOU_TO_THAT_END_I_HAVE                                          = 15710,  -- To help you to that end, I have also prepared something else for you.
        I_ORDERED_THE_A_M_A_N_TO                                                = 15711,  -- I ordered the A.M.A.N. to provide you with a list of Records of Eminence objectives!
        THERE_ARE_THREE_OBJECTIVES_FOR_YOU_TO_COMPLETE                          = 15712,  -- There are three objectives for you to complete. You simply need to complete them all to collect what is necessary!
        AH_THAT_REMINDS_ME_NO_MATTER_WHAT_YOU                                   = 15713,  -- Ah, that reminds me. No matter what, you must not lose this diamond.
        IT_IS_MADE_FROM_AN_EXTREMELY_RARE_GEMSTONE                              = 15714,  -- It is made from an extremely rare gemstone, so I forced my mother's jewelry shop to let me have it.
        IT_WAS_ORIGINALLY_A_RATHER_UNUSUAL_DIAMOND_THAT                         = 15715,  -- It was originally a rather unusual diamond that changed color whenever it sensed a change in the surrounding temperature.
        I_SIMPLY_USED_A_LITTLE_MAGIC_TO_MAKE                                    = 15716,  -- I simply used a little magic to make some key improvements and recreate something from a legend I once heard in a faraway land!
        NOW_THEN_LET_US_BEGIN_THE_EXPERIMENT                                    = 15717,  -- Now then, let us begin the experiment!
        HEY_JUST_WHAT_DO_YOU_THINK_YOU_ARE                                      = 15718,  -- Hey, just what do you think you are doing?
        WHILE_YOU_WERE_DILLYDALLYING_ABOUT_THE_SITUATION_HAS                    = 15719,  -- While you were dillydallying about, the situation has changed! You need to receive % from Lady Syndella first!
        AH_THERE_YOU_ARE_I_WAS_EXPECTING_YOU                                    = 15720,  -- Ah, there you are! I was expecting you much sooner. Hurry up and hand me the diamond already.
        HMM_VERY_WELL_DONE_YOU_HAVE_COLLECTED_JUST                              = 15721,  -- Hmm... Very well done. You have collected just the right amount of thoughts and feelings. Now, for just a touch of magic...
        I_IT_S_A_STAGGERING_SUCCESS_THE_THOUGHTS                                = 15722,  -- I-it's a staggering success! The thoughts have been imbued into the diamond!
        LISTEN_CAREFULLY_YOU_SIMPLY_NEED_TO_USE_THIS                            = 15723,  -- Listen carefully. You simply need to use this diamond as a catalyst when invoking your Trust magic.
        WHEN_YOU_DO_THE_THOUGHTS_SENT_TO_YOUR                                   = 15724,  -- When you do, the thoughts sent to your alter ego when it manifests will be made even more powerful.
        HM_YOU_WISH_TO_KNOW_HOW_TO_USE                                          = 15725,  -- Hm? You wish to know how to use the diamond as a catalyst?
        THAT_IS_SOMETHING_YOU_NEED_TO_FIGURE_OUT                                = 15726,  -- That...is something you need to figure out for yourself!
        AT_ANY_RATE_I_SHALL_GIVE_YOU_THIS                                       = 15727,  -- At any rate, I shall give you this gift for helping me. I feel that it should prove useful to you.
        I_AM_LOOKING_FORWARD_TO_THE_RESULTS_OF                                  = 15728,  -- I am looking forward to the results of your research!
        AH_HELLO_AGAIN_HM_YOU_STILL_HAVE_YET                                    = 15729,  -- Ah, hello again! Hm? You still have yet to acquire %? Please go and receive one from Lady Syndella at once!
        AH_HELLO_AGAIN_I_REMEMBER_YOU_HELPED_ME                                 = 15730,  -- Ah, hello again! I remember you helped me with my research before.
        I_WAS_JUST_THINKING_THAT_I_HAD_YET                                      = 15731,  -- I was just thinking that I had yet to sufficiently compensate you for your efforts. Here, please take this as a token of my gratitude.
        HM_I_FEEL_THAT_THIS_SUBJECT_IS_BEYOND                                   = 15732,  -- Hm... I feel that this subject is beyond your current abilities. Please come speak to me again when you are able to use Trust magic.
        HELLO_THERE_I_FEEL_YOU_ARE_NOT_READY                                    = 15733,  -- Hello there. I feel you are not ready for what I have to teach. Come back once you have obtained %.
        HM_LET_ME_SEE_YES_I_THINK_YOU                                           = 15734,  -- Hm, let me see... Yes, I think you shall do nicely.
        MY_NAME_IS_SYNDELLA_I_AM_CURRENTLY_RESEARCHING                          = 15735,  -- My name is Syndella. I am currently researching the art of Trust magic.
        I_SUPPOSE_YOU_COULD_SAY_THAT_I_SERVE                                    = 15736,  -- I suppose you could say that I serve as a sort of supervisor for Jamal and Marjory.
        THEY_BOTH_BRING_A_UNIQUE_PERSPECTIVE_TO_THEIR                           = 15737,  -- They both bring a unique perspective to their research, so I find them to be quite stimulating.
        BASED_ON_THE_RESULTS_OF_JAMAL_S_RESEARCH                                = 15738,  -- Based on the results of Jamal's research, I started thinking of ways to further strengthen the alter egos that we summon.
        I_DISCOVERED_THAT_THE_WAY_TO_MAKE_THEM                                  = 15739,  -- I discovered that the way to make them more powerful is to strengthen the bond they share with the user when summoned.
        JAMAL_KEEPS_GOING_ON_ABOUT_DARKNESS_BASED_TRUST                         = 15740,  -- Jamal keeps going on about darkness-based Trust magic and unfinished ciphers, but...
        DOCTOR_SHANTOTTO_ONCE_SAID_THAT_TRUST_MAGIC_IS                          = 15741,  -- Doctor Shantotto once said that Trust magic is based on the bond formed between the user and the alter ego.
        SHE_KNEW_THE_ANSWERS_I_SOUGHT_ALL_ALONG                                 = 15742,  -- She knew the answers I sought all along, but I suppose it is only natural, given how dedicated she is to such matters.
        THAT_IS_ENOUGH_IDLE_CHITCHAT_SO_WILL_YOU                                = 15743,  -- That is enough idle chitchat. So, will you help me with my research?
        HELP_WITH_HER_RESEARCH_SURE_SORRY_I_M                                   = 15744,  -- Help with her research? Sure. Sorry, I'm busy.
        AH_THAT_IS_A_SHAME_WELL_PLEASE_COME                                     = 15745,  -- Ah, that is a shame! Well, please come see me if you ever change your mind.
        OH_THANK_YOU_SO_MUCH_NOW_THEN_WITHOUT                                   = 15746,  -- Oh, thank you so much! Now then, without further ado, let's get started.
        PLEASE_PUT_ON_THE_I_JUST_GAVE_YOU                                       = 15747,  -- Please put on the % I just gave you.
        THE_BRACELET_IS_IMBUED_WITH_MAGIC_BASED_ON                              = 15748,  -- The bracelet is imbued with magic based on Jamal's research into the strengthening of bonds between us and the alter egos.
        THE_PROCESS_IS_AUTOMATICALLY_ACTIVATED_IF_YOU_SUMMON                    = 15749,  -- The process is automatically activated if you summon an alter ego while wearing the bracelet. It should serve to make the alter ego even more powerful.
        IT_SEEMS_JAMAL_ATTEMPTED_TO_USE_A_CIPHER                                = 15750,  -- It seems Jamal attempted to use a cipher for the procedure, but there are limits, both physical and magical, to what it can accomplish.
        SO_WHAT_SHOULD_WE_DO_YOU_ASK_THE                                        = 15751,  -- So what should we do, you ask? The answer is to not rely on such ciphers at all.
        IN_OTHER_WORDS_I_WISH_TO_EXPAND_UPON                                    = 15752,  -- In other words, I wish to expand upon the procedure's potential, so I have prepared a special catalyst to help do so.
        AH_I_GOT_LOST_IN_THOUGHT_FOR_A                                          = 15753,  -- Ah, I got lost in thought for a moment there! My apologies!
        THAT_REMINDS_ME_I_FORGOT_TO_MENTION_THAT                                = 15754,  -- That reminds me... I forgot to mention that simply wearing the bracelet is not enough.
        YOU_NEED_TO_ACCUMULATE_WHAT_ARE_KNOWN_AS                                = 15755,  -- You need to accumulate what are known as alter ego points with the bracelet.
        THESE_ALTER_EGO_POINTS_CAN_BE_ACQUIRED_BY                               = 15756,  -- These alter ego points can be acquired by using %.
        FIRST_YOU_ACCUMULATE_THE_ALTER_EGO_POINTS_AND                           = 15757,  -- First, you accumulate the alter ego points and then apply them to the area you wish to strengthen, which serves to enhance the bracelet's magic.
        TO_APPLY_THE_ALTER_EGO_POINTS_GO_TO                                     = 15758,  -- To apply the alter ego points, go to the Main Menu and select Status, followed by Alter Ego Points.
        YOU_CAN_INCREASE_THEIR_ATTRIBUTES_THERE_BUT_ONLY                        = 15759,  -- You can increase their attributes there, but only from your Mog House or Mog Garden.
        ONCE_YOU_HAVE_APPLIED_THE_ALTER_EGO_POINTS                              = 15760,  -- Once you have applied the alter ego points, there are no takebacks. Be aware!
        YOU_ARE_OVERWHELMED_WITH_A_SPECIAL_MAGICAL_FORCE                        = 15761,  -- You are overwhelmed with a special magical force.
        THERE_NOW_YOUR_BRACELET_WILL_NEVER_COME_OFF                             = 15762,  -- There. Now your bracelet will never come off!
        NOW_THEN_I_WISH_YOU_THE_BEST_OF                                         = 15763,  -- Now then, I wish you the best of luck.
        AH_MY_RESEARCH_IS_GOING_QUITE_SPLENDIDLY_YOU                            = 15764,  -- Ah, my research is going quite splendidly. You see, I am able to observe your efforts through the bracelet.
        IT_APPEARS_THAT_YOU_HAVE_ARRIVED_AT_A                                   = 15765,  -- It appears that you have arrived at a new survival guide provided by the Adventurers' Mutual Aid Network. Common sense dictates that you should now be able to teleport here from similar tomes throughout the world.
        BEFORE_YOU_LIES_A_SURVIVAL_GUIDE_PENNED_BY                              = 15766,  -- Before you lies a survival guide penned by the Adventurers' Mutual Aid Network. It touches on such topics as teleportation and battle records.
        IT_APPEARS_THAT_YOU_HAVE_ARRIVED_AT_A_2                                 = 15767,  -- It appears that you have arrived at a new survival guide provided by the Servicemen's Mutual Aid Network. Common sense dictates that you should now be able to teleport here from similar tomes throughout the world.
        BEFORE_YOU_LIES_A_SURVIVAL_GUIDE_PENNED_BY_2                            = 15768,  -- Before you lies a survival guide penned by the Servicemen's Mutual Aid Network. It touches on such topics as teleportation and battle records.
        WHAT_CHAPTER_WILL_YOU_READ_NONE_TELEPORTATION_ASSISTANCE                = 15769,  -- What chapter will you read? None. Teleportation Assistance. Field Support. Other mysteries.
        THE_METICULOUSLY_ILLUMINATED_TEXT_WITHIN_EXPLAINS_THAT_ADVENTURERS      = 15770,  -- The meticulously illuminated text within explains that adventurers may travel to the location of any previous books visited after paying a sum of gil or the requisite amount of tabs.
        NO_OTHER_SURVIVAL_GUIDE_LOCATIONS_HAVE_BEEN_RECORDED                    = 15771,  -- No other survival guide locations have been recorded. Visiting another one would certainly alleviate this issue.
        WHERE_WILL_YOU_TRAVEL_NOWHERE_PREVIOUS_PAGE_NEXT                        = 15772,  -- Where will you travel? Nowhere. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. Previous page. Next page.
        IT_WILL_COST_GIL_TO_TELEPORT_TO_GIL                                     = 15773,  -- It will cost # gil to teleport to %. (# gil on hand)
        ALL_MOG_TABLETS_HAVE_CURRENTLY_BEEN_FOUND_SO                            = 15774,  -- All mog tablets have currently been found, so you may teleport to % at no charge.
        TRAVEL_TO_UP_AND_AWAY_I_M_DOWN                                          = 15775,  -- Travel to %? [Add to favorites/Delete from favorites]. Up and away! I'm down and out.
        TRAVEL_TO_TRAVEL_USING_GIL_GIL_TRAVEL_USING                             = 15776,  -- Travel to %? [Add to favorites/Delete from favorites]. Travel using # gil. (# gil) Travel using # tab[/s]. (# total) One-time free Warp for the objective. Not just yet.
        YOU_DO_NOT_HAVE_ENOUGH_TABS                                             = 15777,  -- You do not have enough tabs.
        THE_RECORDS_INDICATE_YOU_HAVE_FOUGHT_VALIANTLY_FOR                      = 15778,  -- The records indicate you have fought valiantly for Vana'diel for # hour[/s].
        AT_THE_BOTTOM_OF_THE_PAGE_IS_A                                          = 15779,  -- At the bottom of the page is a reminder. It perfunctorily states that you may receive % once you have logged a total of # hours.
        AS_PER_THE_CUSTOM_NOTED_WITHIN_YOU_ARE                                  = 15780,  -- As per the custom noted within, you are eligible to receive % for the # hour[/s] of fighting you've accrued.
        ACCEPT_THE_REWARD_YES_PLEASE_NO_THANKS                                  = 15781,  -- Accept the reward? Yes, please. No, thanks.
