        UM_MISS_THIS_ISN_T_AN_ACTUAL_SHOW                                       = 16163,  -- Um, miss? This isn't an actual show, you see. We're still holding auditions.
        YOU_RE_WHAT_ARE_YOU_SERIOUS                                             = 16164,  -- You're what!? Are you serious!?
        HEH_HEH_MAAT_HERE_SAID_HE_WANTED_TO                                     = 16165,  -- Heh heh... Maat here said he wanted to be a part of the Goblin festival too.
        I_GUESS_HIS_PERFORMANCE_IN_THE_AUDITION_WAS                             = 16166,  -- I guess his performance in the audition was a little too...passionate. We're sorry for all the fuss.
        YOU_CAN_SAY_THAT_AGAIN_THE_FESTIVAL_OF                                  = 16167,  -- You can say that again! The Festival of Brave Souls was canceled because of you!
        I_DON_T_THINK_YOU_UNDERSTAND_JUST_HOW                                   = 16168,  -- I don't think you understand just how serious this is!
        UNGH_I_DON_T_REMEMBER_ANY_OF_THAT                                       = 16169,  -- Ungh... I don't remember any of that...
        SOMEHOW_I_FOUND_MYSELF_COVERED_IN_VARIOUS_SCRAPES                       = 16170,  -- Somehow, I found myself covered in various scrapes and bruises. Maybe that's how I lost my memories?
        AH                                                                      = 16171,  -- Ah!
