        UM                                                                      = 16174,  -- Um...
        NO_IT_WAS_ALL_MY_FAULT_AT_LEAST                                         = 16175,  -- No, it was all my fault. At least those people I scared can rest easily now.
        WELL_I_SUPPOSE_YOU_RE_RIGHT_I_HEAR                                      = 16176,  -- Well, I suppose you're right. I hear the Goblins have resumed preparations for their festival as well.
