        OH_YES_OF_COURSE_I_LL_GO_AT                                             = 16179,  -- Oh, yes, of course! I'll go at once!
        NOW_THEN_YOU_THERE_YOU_LOOK_FAMILIAR                                    = 16180,  -- Now then... You there. You look familiar.
        I_M_SHAMI_WE_VE_CONDUCTED_SOME_BUSINESS                                 = 16181,  -- I'm Shami. We've conducted some business together in the past.
        MY_NAME_IS_SHAMI_I_TRADE_IN_RATHER                                      = 16182,  -- My name is Shami. I trade in rather unusual items back in Port Jeuno with adventurers much like yourself.
